import { TraceEvalAgentScreen } from "@/components/trace-eval-agent/trace-eval-agent-screen";

export default function TraceEvalAgentPage() {
  return <TraceEvalAgentScreen />;
}

import { handleTraceEvalAgentRequest } from "@/lib/trace-eval-agent/server/runtime";

export const runtime = "nodejs";

export function POST(request: Request) {
  return handleTraceEvalAgentRequest(request);
}

import { handleTraceEvalAgentEvaluationRequest } from "@/lib/trace-eval-agent/server/evaluation";

export const runtime = "nodejs";

export function POST(request: Request) {
  return handleTraceEvalAgentEvaluationRequest(request);
}

import { handleTraceEvalAgentEvaluationStreamRequest } from "@/lib/trace-eval-agent/server/evaluation";

export const runtime = "nodejs";

export function POST(request: Request) {
  return handleTraceEvalAgentEvaluationStreamRequest(request);
}

"use client";

import { MagnifyingGlassIcon, StopIcon } from "@phosphor-icons/react";
import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { useDeferredValue } from "react";
import { classifyTraceEvalRunOutcome } from "@/lib/trace-eval-agent/model/trace-eval-run-outcome";
import { buildTraceEvalRunRecord } from "@/lib/trace-eval-agent/model/trace-eval-run-record";
import { buildTraceEvalSnapshotFromRunRecord } from "@/lib/trace-eval-agent/model/trace-eval-snapshot";
import type { TraceEvalAgentRuntimeState } from "@/lib/trace-eval-agent/server/runtime";
import { TraceEvalAgentAssistantMessage } from "./trace-eval-agent-assistant-message";
import { TraceEvalAgentEvalPanel } from "./trace-eval-agent-eval-panel";
import {
  getTextContent,
  traceEvalAgentSamplePrompts,
} from "./trace-eval-agent-model";
import { TraceEvalAgentRuntimeSidebar } from "./trace-eval-agent-runtime-sidebar";
import { TraceEvalAgentTracePanel } from "./trace-eval-agent-trace-panel";
import { useTraceEvalAgentChat } from "./use-trace-eval-agent-chat";
import { useTraceEvalJudge } from "./use-trace-eval-judge";

interface TraceEvalAgentWorkspaceProps {
  runtimeState: TraceEvalAgentRuntimeState;
}

export function TraceEvalAgentWorkspace({
  runtimeState,
}: TraceEvalAgentWorkspaceProps) {
  const {
    clearError,
    error,
    hasMessages,
    isBusy,
    messages,
    regenerate,
    sendMessage,
    status,
    stop,
  } = useTraceEvalAgentChat();
  const deferredMessages = useDeferredValue(messages);
  const runRecord = buildTraceEvalRunRecord(deferredMessages, isBusy);
  const snapshot = buildTraceEvalSnapshotFromRunRecord(runRecord);
  const runOutcome = classifyTraceEvalRunOutcome({
    error,
    record: runRecord,
  });
  const judge = useTraceEvalJudge({
    judgeModel: runtimeState.chatModel,
    outcome: runOutcome,
    snapshot,
  });

  function resetTransientFailure() {
    clearError();
  }

  async function handleSendMessage(text: string) {
    resetTransientFailure();
    await sendMessage({ text });
  }

  async function handleRetry() {
    resetTransientFailure();
    await regenerate();
  }

  return (
    <div className="grid min-h-[70svh] gap-4 lg:h-full lg:min-h-0 lg:grid-cols-[minmax(0,1fr)_22rem]">
      <section className="grid min-h-[70svh] gap-4 lg:h-full lg:min-h-0 lg:grid-rows-[minmax(0,1fr)_22rem]">
        <div className="flex min-h-[30rem] flex-col border border-foreground/10 bg-background lg:min-h-0">
          {runtimeState.isChatAvailable ? null : (
            <div className="border-foreground/10 border-b px-4 py-3 text-muted-foreground text-xs/relaxed">
              {runtimeState.setupMessage}
            </div>
          )}

          {runOutcome.kind === "failed-run" ? (
            <div className="flex items-center justify-between gap-4 border-foreground/10 border-b px-4 py-3 text-xs/relaxed">
              <p className="text-destructive">{runOutcome.detail}</p>
              <Button
                onClick={() => {
                  handleRetry();
                }}
                size="sm"
                type="button"
                variant="outline"
              >
                Retry
              </Button>
            </div>
          ) : null}

          <Conversation className="min-h-0 flex-1">
            <ConversationContent className="mx-auto flex w-full max-w-4xl flex-1 gap-6 px-4 pt-6 pb-[3lh]">
              {hasMessages ? (
                messages.map((message, index) => (
                  <Message from={message.role} key={message.id}>
                    <MessageContent
                      className={cn(
                        "space-y-4",
                        message.role === "assistant" ? "max-w-4xl" : "max-w-2xl"
                      )}
                    >
                      {message.role === "assistant" ? (
                        <TraceEvalAgentAssistantMessage
                          isStreaming={isBusy && index === messages.length - 1}
                          message={message}
                        />
                      ) : (
                        <MessageResponse>
                          {getTextContent(message)}
                        </MessageResponse>
                      )}
                    </MessageContent>
                  </Message>
                ))
              ) : (
                <ConversationEmptyState
                  description="Ask for live research. The agent will search the web through AI Gateway, then the trace and eval panel below will score the current conversation."
                  icon={<MagnifyingGlassIcon className="size-5" />}
                  title="Research agent is ready"
                />
              )}
            </ConversationContent>
            <ConversationScrollButton />
          </Conversation>

          <div className="border-foreground/10 border-t px-4 py-4">
            <div className="mx-auto w-full max-w-4xl">
              <PromptInput
                onSubmit={({ text }) => {
                  handleSendMessage(text);
                }}
              >
                <PromptInputBody>
                  <PromptInputTextarea
                    disabled={!runtimeState.isChatAvailable || isBusy}
                    placeholder="Ask the agent to research a topic and ground the answer with live web search."
                  />
                </PromptInputBody>
                <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
                  <div className="flex flex-wrap items-center gap-2">
                    <Badge variant="outline">ResearchAgent</Badge>
                    <Badge variant="outline">Trace + Eval</Badge>
                    <Badge variant="outline">{runtimeState.chatModel}</Badge>
                  </div>
                  <div className="flex items-center gap-2">
                    {isBusy ? (
                      <Button
                        onClick={stop}
                        size="sm"
                        type="button"
                        variant="outline"
                      >
                        <StopIcon className="size-3.5" />
                        Stop
                      </Button>
                    ) : null}
                    {hasMessages ? (
                      <Button
                        onClick={() => {
                          handleRetry();
                        }}
                        size="sm"
                        type="button"
                        variant="outline"
                      >
                        Retry
                      </Button>
                    ) : null}
                    <PromptInputSubmit
                      disabled={!runtimeState.isChatAvailable}
                      status={status}
                    />
                  </div>
                </PromptInputFooter>
              </PromptInput>

              {hasMessages ? null : (
                <div className="mt-3 flex flex-wrap gap-2">
                  {traceEvalAgentSamplePrompts.map((item) => (
                    <Button
                      className="h-auto whitespace-normal text-left [overflow-wrap:anywhere]"
                      key={item.prompt}
                      onClick={() => {
                        handleSendMessage(item.prompt);
                      }}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <MagnifyingGlassIcon className="size-3.5" />
                      {item.label}
                    </Button>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="grid gap-4 lg:grid-cols-[minmax(0,1.1fr)_minmax(0,0.9fr)]">
          <TraceEvalAgentTracePanel
            runOutcome={runOutcome}
            snapshot={snapshot}
          />
          <TraceEvalAgentEvalPanel
            judge={judge}
            runOutcome={runOutcome}
            snapshot={snapshot}
          />
        </div>
      </section>

      <TraceEvalAgentRuntimeSidebar
        judge={judge}
        onPromptSelect={(prompt) => {
          handleSendMessage(prompt);
        }}
        runOutcome={runOutcome}
        runtimeState={runtimeState}
        snapshot={snapshot}
      />
    </div>
  );
}

"use client";

import { MessageResponse } from "@/components/ai-elements/message";
import {
  Reasoning,
  ReasoningContent,
  ReasoningTrigger,
} from "@/components/ai-elements/reasoning";
import { Shimmer } from "@/components/ai-elements/shimmer";
import {
  Source,
  Sources,
  SourcesContent,
  SourcesTrigger,
} from "@/components/ai-elements/sources";
import {
  Tool,
  ToolContent,
  ToolHeader,
  ToolInput,
  ToolOutput,
} from "@/components/ai-elements/tool";
import type { UIMessage } from "ai";

import { buildTraceEvalSnapshot } from "@/lib/trace-eval-agent/model/trace-eval-snapshot";
import {
  getReasoningText,
  getTextContent,
  getToolDisplayName,
  getToolParts,
  hasVisibleToolPayload,
} from "./trace-eval-agent-model";

interface TraceEvalAgentAssistantMessageProps {
  isStreaming: boolean;
  message: UIMessage;
}

export function TraceEvalAgentAssistantMessage({
  isStreaming,
  message,
}: TraceEvalAgentAssistantMessageProps) {
  const reasoning = getReasoningText(message);
  const answer = getTextContent(message);
  const toolParts = getToolParts(message).filter(hasVisibleToolPayload);
  const hasReasoning = reasoning.length > 0;
  const hasAnswer = answer.length > 0;
  const lastPart = message.parts.at(-1);
  const isReasoningStreaming = isStreaming && lastPart?.type === "reasoning";
  const showThinking = isStreaming && !hasReasoning && !hasAnswer;
  const snapshot = buildTraceEvalSnapshot([message], isStreaming);

  return (
    <div className="space-y-4">
      {hasReasoning ? (
        <Reasoning
          className="rounded-md border border-foreground/10 px-3 py-2"
          isStreaming={isReasoningStreaming}
        >
          <ReasoningTrigger />
          <ReasoningContent>{reasoning}</ReasoningContent>
        </Reasoning>
      ) : null}

      {toolParts.map((part) => (
        <Tool className="bg-muted/20" key={part.toolCallId}>
          {part.type === "dynamic-tool" ? (
            <ToolHeader
              state={part.state}
              title={getToolDisplayName(part)}
              toolName={part.toolName}
              type={part.type}
            />
          ) : (
            <ToolHeader
              state={part.state}
              title={getToolDisplayName(part)}
              type={part.type}
            />
          )}
          <ToolContent>
            {part.input ? <ToolInput input={part.input} /> : null}
            <ToolOutput errorText={part.errorText} output={part.output} />
          </ToolContent>
        </Tool>
      ))}

      {snapshot.sources.length > 0 ? (
        <Sources>
          <SourcesTrigger count={snapshot.sources.length} />
          <SourcesContent>
            {snapshot.sources.map((source) => (
              <Source href={source.url} key={source.url} title={source.title} />
            ))}
          </SourcesContent>
        </Sources>
      ) : null}

      {hasAnswer ? <MessageResponse>{answer}</MessageResponse> : null}
      {showThinking ? <Shimmer className="text-sm">Thinking...</Shimmer> : null}
    </div>
  );
}

"use client";

import {
  CheckCircleIcon,
  CircleIcon,
  CircleNotchIcon,
  XCircleIcon,
} from "@phosphor-icons/react";
import {
  Task,
  TaskContent,
  TaskItem,
  TaskTrigger,
} from "@/components/ai-elements/task";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";

import type { TraceEvalRunOutcome } from "@/lib/trace-eval-agent/model/trace-eval-run-outcome";
import type { TraceEvalSnapshot } from "@/lib/trace-eval-agent/model/trace-eval-snapshot";

const traceStatusStyles = {
  failed: "text-red-600",
  passed: "text-green-600",
  pending: "text-muted-foreground",
  running: "text-blue-600",
} as const;

const traceStatusIcons = {
  failed: XCircleIcon,
  passed: CheckCircleIcon,
  pending: CircleIcon,
  running: CircleNotchIcon,
} as const;

export function TraceEvalAgentTracePanel({
  runOutcome,
  snapshot,
}: {
  runOutcome: TraceEvalRunOutcome;
  snapshot: TraceEvalSnapshot;
}) {
  if (runOutcome.kind === "failed-run") {
    return (
      <section className="min-h-0 overflow-y-auto rounded-lg border border-foreground/10 bg-background p-4">
        <div className="mb-4 flex items-center justify-between gap-3">
          <div>
            <h2 className="font-medium text-sm">Trace</h2>
            <p className="text-muted-foreground text-xs">
              Current conversation execution path
            </p>
          </div>
          <Badge variant="outline">failed</Badge>
        </div>

        <Task defaultOpen>
          <TaskTrigger title={runOutcome.title} />
          <TaskContent>
            <TaskItem className="space-y-1">
              <div className="flex items-start gap-2">
                <XCircleIcon className="mt-0.5 size-4 shrink-0 text-red-600" />
                <div className="min-w-0">
                  <p className="font-medium text-foreground text-sm">
                    Run failed before trace evaluation
                  </p>
                  <p className="text-muted-foreground text-xs/relaxed">
                    {runOutcome.detail}
                  </p>
                </div>
              </div>
            </TaskItem>
          </TaskContent>
        </Task>
      </section>
    );
  }

  return (
    <section className="min-h-0 overflow-y-auto rounded-lg border border-foreground/10 bg-background p-4">
      <div className="mb-4 flex items-center justify-between gap-3">
        <div>
          <h2 className="font-medium text-sm">Trace</h2>
          <p className="text-muted-foreground text-xs">
            Current conversation execution path
          </p>
        </div>
        <Badge variant="outline">{snapshot.status}</Badge>
      </div>

      <Task defaultOpen>
        <TaskTrigger title="Execution trace" />
        <TaskContent>
          {snapshot.trace.map((item) => {
            const Icon = traceStatusIcons[item.status];

            return (
              <TaskItem className="space-y-1" key={item.id}>
                <div className="flex items-start justify-between gap-3">
                  <div className="flex min-w-0 items-center gap-2">
                    <Icon
                      className={cn(
                        "mt-0.5 size-4 shrink-0",
                        traceStatusStyles[item.status]
                      )}
                    />
                    <div className="min-w-0">
                      <p className="font-medium text-foreground text-sm">
                        {item.title}
                      </p>
                      <p className="text-muted-foreground text-xs/relaxed">
                        {item.detail}
                      </p>
                    </div>
                  </div>
                  {item.metric ? (
                    <Badge className="shrink-0" variant="outline">
                      {item.metric}
                    </Badge>
                  ) : null}
                </div>
              </TaskItem>
            );
          })}
        </TaskContent>
      </Task>
    </section>
  );
}

"use client";

import {
  Test,
  TestName,
  TestResults,
  TestResultsContent,
  TestResultsDuration,
  TestResultsHeader,
  TestResultsProgress,
  TestResultsSummary,
  TestStatus,
  TestSuite,
  TestSuiteContent,
  TestSuiteName,
  TestSuiteStats,
} from "@/components/ai-elements/test-results";

import type { TraceEvalRunOutcome } from "@/lib/trace-eval-agent/model/trace-eval-run-outcome";
import type { TraceEvalSnapshot } from "@/lib/trace-eval-agent/model/trace-eval-snapshot";
import type { TraceEvalJudgeViewState } from "./use-trace-eval-judge";

export function TraceEvalAgentEvalPanel({
  judge,
  runOutcome,
  snapshot,
}: {
  judge: TraceEvalJudgeViewState;
  runOutcome: TraceEvalRunOutcome;
  snapshot: TraceEvalSnapshot;
}) {
  if (runOutcome.kind === "empty") {
    return (
      <TestResults
        className="min-h-0 overflow-y-auto rounded-lg border-foreground/10"
        summary={{
          duration: undefined,
          failed: 0,
          passed: 0,
          skipped: 0,
          total: 0,
        }}
      >
        <TestResultsHeader>
          <div>
            <h2 className="font-medium text-sm">Eval</h2>
            <p className="text-muted-foreground text-xs">
              Deterministic gate and LLM judge
            </p>
          </div>
        </TestResultsHeader>

        <TestResultsContent>
          <p className="text-muted-foreground text-sm/relaxed">
            {runOutcome.detail}
          </p>
        </TestResultsContent>
      </TestResults>
    );
  }

  if (runOutcome.kind === "skipped") {
    return (
      <TestResults
        className="min-h-0 overflow-y-auto rounded-lg border-foreground/10"
        summary={{
          duration: snapshot.durationMs,
          failed: 0,
          passed: 0,
          skipped: snapshot.summary.total,
          total: snapshot.summary.total,
        }}
      >
        <TestResultsHeader>
          <div>
            <h2 className="font-medium text-sm">Eval</h2>
            <p className="text-muted-foreground text-xs">
              Deterministic gate and LLM judge
            </p>
          </div>
          <div className="flex items-center gap-3">
            <TestResultsDuration />
            <TestResultsSummary />
          </div>
        </TestResultsHeader>

        <TestResultsContent>
          <TestSuite defaultOpen name={runOutcome.title} status="skipped">
            <div className="flex items-center">
              <TestSuiteName />
              <TestSuiteStats
                failed={0}
                passed={0}
                skipped={snapshot.summary.total}
              />
            </div>
            <TestSuiteContent>
              <Test name="Evaluation skipped" status="skipped">
                <TestStatus />
                <div className="flex-1">
                  <TestName />
                  <p className="text-muted-foreground text-xs/relaxed">
                    {runOutcome.detail}
                  </p>
                </div>
              </Test>
            </TestSuiteContent>
          </TestSuite>
        </TestResultsContent>
      </TestResults>
    );
  }

  if (runOutcome.kind === "failed-run") {
    return (
      <TestResults
        className="min-h-0 overflow-y-auto rounded-lg border-foreground/10"
        summary={{
          duration: snapshot.durationMs,
          failed: 1,
          passed: 0,
          skipped: 0,
          total: 1,
        }}
      >
        <TestResultsHeader>
          <div>
            <h2 className="font-medium text-sm">Eval</h2>
            <p className="text-muted-foreground text-xs">
              Deterministic gate and LLM judge
            </p>
          </div>
          <div className="flex items-center gap-3">
            <TestResultsDuration />
            <TestResultsSummary />
          </div>
        </TestResultsHeader>

        <TestResultsContent>
          <TestSuite defaultOpen name={runOutcome.title} status="failed">
            <div className="flex items-center">
              <TestSuiteName />
              <TestSuiteStats failed={1} passed={0} skipped={0} />
            </div>
            <TestSuiteContent>
              <Test name="Run failed before judging" status="failed">
                <TestStatus />
                <div className="flex-1">
                  <TestName />
                  <p className="text-muted-foreground text-xs/relaxed">
                    {runOutcome.detail}
                  </p>
                </div>
              </Test>
            </TestSuiteContent>
          </TestSuite>
        </TestResultsContent>
      </TestResults>
    );
  }

  let suiteStatus: "failed" | "passed" | "running" = "passed";

  if (snapshot.summary.failed > 0) {
    suiteStatus = "failed";
  } else if (snapshot.status === "running") {
    suiteStatus = "running";
  }

  const judgeSuiteStatus = getJudgeSuiteStatus(judge);

  return (
    <TestResults
      className="min-h-0 overflow-y-auto rounded-lg border-foreground/10"
      summary={{
        duration: snapshot.durationMs,
        ...snapshot.summary,
      }}
    >
      <TestResultsHeader>
        <div>
          <h2 className="font-medium text-sm">Eval</h2>
          <p className="text-muted-foreground text-xs">
            Deterministic gate and LLM judge
          </p>
        </div>
        <div className="flex items-center gap-3">
          <TestResultsDuration />
          <TestResultsSummary />
        </div>
      </TestResultsHeader>

      <TestResultsContent className="space-y-4">
        <div className="space-y-2">
          <div className="flex items-center justify-between text-xs">
            <span className="text-muted-foreground">Gate score</span>
            <span className="font-medium">{formatScore(snapshot.score)}</span>
          </div>
          {judge.result ? (
            <div className="flex items-center justify-between text-xs">
              <span className="text-muted-foreground">Judge score</span>
              <span className="font-medium">
                {formatScore(judge.result.overallScore)}
              </span>
            </div>
          ) : null}
          {judge.status === "running" ? (
            <div className="space-y-2">
              <div className="flex items-center justify-between gap-3 text-xs">
                <span className="text-muted-foreground">Judge progress</span>
                <span className="font-medium">
                  {formatScore(getJudgeProgressValue(judge))}
                </span>
              </div>
              <div className="h-2 overflow-hidden rounded-full bg-foreground/10">
                <div
                  className="h-full bg-blue-600 transition-[width] duration-300"
                  style={{
                    width: `${Math.max(6, Math.round(getJudgeProgressValue(judge) * 100))}%`,
                  }}
                />
              </div>
            </div>
          ) : null}
          <TestResultsProgress />
        </div>

        <TestSuite defaultOpen name="Current conversation" status={suiteStatus}>
          <div className="flex items-center">
            <TestSuiteName />
            <TestSuiteStats
              failed={snapshot.summary.failed}
              passed={snapshot.summary.passed}
              skipped={snapshot.summary.skipped}
            />
          </div>
          <TestSuiteContent>
            {snapshot.checks.map((check) => (
              <Test key={check.id} name={check.title} status={check.status}>
                <TestStatus />
                <div className="flex-1">
                  <TestName />
                  <p className="text-muted-foreground text-xs/relaxed">
                    {check.detail}
                  </p>
                </div>
              </Test>
            ))}
          </TestSuiteContent>
        </TestSuite>

        <TestSuite defaultOpen name="LLM judge" status={judgeSuiteStatus}>
          <div className="flex items-center">
            <TestSuiteName />
            {judge.result ? (
              <TestSuiteStats
                failed={judge.result.deterministicFailures.length}
                passed={
                  judge.result.dimensions.filter(
                    (dimension) => dimension.score >= 0.8
                  ).length
                }
                skipped={
                  judge.result.dimensions.filter(
                    (dimension) =>
                      dimension.score >= 0.6 && dimension.score < 0.8
                  ).length
                }
              />
            ) : null}
          </div>
          <TestSuiteContent>
            {renderJudgeContent(judge, runOutcome, snapshot)}
          </TestSuiteContent>
        </TestSuite>
      </TestResultsContent>
    </TestResults>
  );
}

function getJudgeSuiteStatus(
  judge: TraceEvalJudgeViewState
): "failed" | "passed" | "running" | "skipped" {
  if (judge.status === "running") {
    return "running";
  }

  if (judge.status === "idle") {
    return "skipped";
  }

  if (judge.status === "failed") {
    return "failed";
  }

  if (
    judge.result &&
    (judge.result.overallScore < 0.8 ||
      judge.result.deterministicFailures.length > 0)
  ) {
    return "failed";
  }

  return "passed";
}

function getDimensionStatus(score: number): "failed" | "passed" | "skipped" {
  if (score >= 0.8) {
    return "passed";
  }

  return score >= 0.6 ? "skipped" : "failed";
}

function formatScore(score: number) {
  return `${Math.round(score * 100)}%`;
}

function getJudgeProgressValue(judge: TraceEvalJudgeViewState) {
  return judge.progress?.progress ?? 0;
}

function formatJudgeElapsed(judge: TraceEvalJudgeViewState) {
  if (judge.elapsedMs === null) {
    return "Elapsed time is still starting.";
  }

  return `Elapsed ${Math.max(0.1, judge.elapsedMs / 1000).toFixed(1)}s`;
}

function formatJudgeStageLabel(
  step: "starting" | "summary" | "dimensions" | "finalizing"
) {
  switch (step) {
    case "starting":
      return "Starting";
    case "summary":
      return "Streaming summary";
    case "dimensions":
      return "Scoring dimensions";
    case "finalizing":
      return "Finalizing recommendation";
    default:
      return "Judge stage";
  }
}

function renderJudgeContent(
  judge: TraceEvalJudgeViewState,
  runOutcome: TraceEvalRunOutcome,
  snapshot: TraceEvalSnapshot
) {
  if (judge.status === "idle") {
    if (runOutcome.kind === "running") {
      return (
        <Test name="Waiting for completed run" status="running">
          <TestStatus />
          <div className="flex-1">
            <TestName />
            <p className="text-muted-foreground text-xs/relaxed">
              The run is still streaming. The judge starts after the research
              answer completes.
            </p>
          </div>
        </Test>
      );
    }

    if (snapshot.latestPrompt && !snapshot.latestAnswer) {
      return (
        <Test name="Retry required before judging" status="skipped">
          <TestStatus />
          <div className="flex-1">
            <TestName />
            <p className="text-muted-foreground text-xs/relaxed">
              The judge only runs after a completed research answer is
              available. Retry the run to generate an answer before scoring it.
            </p>
          </div>
        </Test>
      );
    }

    return (
      <Test name="Waiting for completed run" status="skipped">
        <TestStatus />
        <div className="flex-1">
          <TestName />
          <p className="text-muted-foreground text-xs/relaxed">
            The judge starts after the research answer finishes.
          </p>
        </div>
      </Test>
    );
  }

  if (judge.status === "running") {
    return (
      <>
        <Test
          name={`Evaluating answer and run${
            judge.progress
              ? `: ${formatJudgeStageLabel(judge.progress.step)}`
              : ""
          }`}
          status="running"
        >
          <TestStatus />
          <div className="flex-1">
            <TestName />
            <p className="text-muted-foreground text-xs/relaxed">
              {judge.progress?.message ??
                "Scoring final-answer quality and full-run quality."}
            </p>
            <p className="mt-1 text-muted-foreground text-xs/relaxed">
              {formatJudgeElapsed(judge)}
            </p>
          </div>
        </Test>

        {judge.partial?.summary ? (
          <Test name="Partial summary" status="running">
            <TestStatus />
            <div className="flex-1">
              <TestName />
              <p className="text-muted-foreground text-xs/relaxed">
                {judge.partial.summary}
              </p>
            </div>
          </Test>
        ) : null}

        {judge.partial?.dimensions?.map((dimension) =>
          dimension ? (
            <Test
              key={
                dimension.id ??
                dimension.title ??
                dimension.rationale ??
                "streaming-dimension"
              }
              name={dimension.title ?? "Streaming dimension"}
              status="running"
            >
              <TestStatus />
              <div className="flex-1">
                <TestName />
                <p className="text-muted-foreground text-xs/relaxed">
                  {dimension.rationale ?? "Scoring dimension."}
                </p>
              </div>
            </Test>
          ) : null
        )}
      </>
    );
  }

  if (judge.status === "failed") {
    return (
      <Test name="Judge request failed" status="failed">
        <TestStatus />
        <div className="flex-1">
          <TestName />
          <p className="text-muted-foreground text-xs/relaxed">{judge.error}</p>
        </div>
      </Test>
    );
  }

  if (!judge.result) {
    return null;
  }

  return (
    <>
      <Test
        name={`Overall: ${judge.result.action}`}
        status={getJudgeSuiteStatus(judge)}
      >
        <TestStatus />
        <div className="flex-1">
          <TestName />
          <p className="text-muted-foreground text-xs/relaxed">
            {judge.result.summary}
          </p>
          <p className="mt-1 text-muted-foreground text-xs/relaxed">
            {judge.result.rationale}
          </p>
        </div>
      </Test>

      {judge.result.deterministicFailures.length > 0 ? (
        <Test name="Hard gate failures" status="failed">
          <TestStatus />
          <div className="flex-1">
            <TestName />
            <p className="text-muted-foreground text-xs/relaxed">
              {judge.result.deterministicFailures
                .map((failure) => failure.title)
                .join(", ")}
            </p>
          </div>
        </Test>
      ) : null}

      {judge.result.dimensions.map((dimension) => (
        <Test
          key={dimension.id}
          name={`${dimension.title}: ${formatScore(dimension.score)}`}
          status={getDimensionStatus(dimension.score)}
        >
          <TestStatus />
          <div className="flex-1">
            <TestName />
            <p className="text-muted-foreground text-xs/relaxed">
              {dimension.rationale}
            </p>
          </div>
        </Test>
      ))}
    </>
  );
}

