import { type UIMessage, validateUIMessages } from "ai";

import { streamTraceEvalAgent } from "./chat";
import {
  getTraceEvalAgentEnv,
  getTraceEvalAgentSetupState,
  type TraceEvalAgentEnv,
} from "./env";
import { resolveTraceEvalAgentChatModel } from "./model";

interface TraceEvalAgentRequestBody {
  messages?: UIMessage[];
}

interface TraceEvalAgentRequestDependencies {
  streamTraceEvalAgent: (
    messages: UIMessage[],
    env: TraceEvalAgentEnv
  ) => Promise<Response> | Response;
}

export interface TraceEvalAgentRuntimeState {
  chatModel: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  setupMessage: string | null;
  statusLabel: "Ready" | "Setup required";
}

const invalidMessagesError = 'Expected a JSON body with a "messages" array.';
const invalidUiMessagesError =
  'Expected each "messages" entry to match the UIMessage format.';

async function readTraceEvalAgentMessages(body: unknown): Promise<UIMessage[]> {
  const { messages } = (body ?? {}) as TraceEvalAgentRequestBody;

  if (!Array.isArray(messages)) {
    throw new Error(invalidMessagesError);
  }

  try {
    return await validateUIMessages({ messages });
  } catch {
    throw new Error(invalidUiMessagesError);
  }
}

export function getTraceEvalAgentRuntimeState(
  env: TraceEvalAgentEnv = getTraceEvalAgentEnv()
): TraceEvalAgentRuntimeState {
  const setup = getTraceEvalAgentSetupState(env);

  return {
    chatModel: resolveTraceEvalAgentChatModel(env),
    isChatAvailable: setup.isReady,
    nodeVersion: setup.nodeVersion,
    setupMessage: setup.issues.length > 0 ? setup.issues.join(" ") : null,
    statusLabel: setup.isReady ? "Ready" : "Setup required",
  };
}

export async function handleTraceEvalAgentRequest(
  request: Request,
  env: TraceEvalAgentEnv = getTraceEvalAgentEnv(),
  dependencies: TraceEvalAgentRequestDependencies = {
    streamTraceEvalAgent,
  }
) {
  const runtimeState = getTraceEvalAgentRuntimeState(env);

  if (!runtimeState.isChatAvailable) {
    return Response.json(
      {
        error: runtimeState.setupMessage,
      },
      { status: 500 }
    );
  }

  try {
    const messages = await readTraceEvalAgentMessages(await request.json());

    return dependencies.streamTraceEvalAgent(messages, env);
  } catch (error) {
    if (
      error instanceof Error &&
      [invalidMessagesError, invalidUiMessagesError].includes(error.message)
    ) {
      return Response.json(
        {
          error: error.message,
        },
        { status: 400 }
      );
    }

    throw error;
  }
}

import { isFileUIPart, isTextUIPart, type UIMessage } from "ai";

import { isTraceEvalRefusalAnswer } from "./trace-eval-run-state";

function getReplayableAssistantText(message: UIMessage) {
  return message.parts
    .filter(isTextUIPart)
    .map((part) => part.text)
    .join("\n")
    .trim();
}

export function projectTraceEvalHistoryForModel(messages: UIMessage[]) {
  return messages.flatMap((message) => {
    if (message.role === "assistant") {
      const text = getReplayableAssistantText(message);

      if (!(text && !isTraceEvalRefusalAnswer(text))) {
        return [];
      }

      return [
        {
          id: message.id,
          parts: [
            {
              text,
              type: "text" as const,
            },
          ],
          role: "assistant" as const,
        },
      ];
    }

    if (message.role === "user") {
      const parts = message.parts.filter(
        (part) => isTextUIPart(part) || isFileUIPart(part)
      );

      return parts.length > 0
        ? [
            {
              ...message,
              parts,
            },
          ]
        : [];
    }

    if (message.role === "system") {
      const parts = message.parts.filter(isTextUIPart);

      return parts.length > 0
        ? [
            {
              ...message,
              parts,
            },
          ]
        : [];
    }

    return [];
  });
}

import type { DeepPartial } from "ai";

import type { TraceEvalJudgeStreamObject } from "./trace-eval-judge";

export type TraceEvalJudgeProgressStep =
  | "starting"
  | "summary"
  | "dimensions"
  | "finalizing";

export interface TraceEvalJudgeProgressState {
  label: string;
  message: string;
  progress: number;
  step: TraceEvalJudgeProgressStep;
}

const startingProgressState: TraceEvalJudgeProgressState = {
  label: "Starting",
  message: "Opening the structured judge stream.",
  progress: 0.08,
  step: "starting",
};

export function deriveTraceEvalJudgeProgress(
  partialJudge: DeepPartial<TraceEvalJudgeStreamObject> | null
): TraceEvalJudgeProgressState {
  if (!partialJudge) {
    return startingProgressState;
  }

  if (partialJudge.action) {
    return {
      label: "Finalizing recommendation",
      message: "The judge is completing the final remediation recommendation.",
      progress: 0.92,
      step: "finalizing",
    };
  }

  if ((partialJudge.dimensions?.length ?? 0) > 0) {
    return {
      label: "Scoring dimensions",
      message: "The judge is filling the dimension-by-dimension scores.",
      progress: 0.72,
      step: "dimensions",
    };
  }

  if (partialJudge.summary || partialJudge.rationale) {
    return {
      label: "Streaming summary",
      message: "The judge is drafting the high-level summary and rationale.",
      progress: 0.32,
      step: "summary",
    };
  }

  return startingProgressState;
}

import { z } from "zod";
import type {
  TraceEvalCheck,
  TraceEvalSnapshot,
  TraceEvalSource,
  TraceEvalTraceItem,
} from "./trace-eval-snapshot";

export type TraceEvalJudgeAction =
  | "ready"
  | "needs-revision"
  | "rerun-research"
  | "investigate-failure";

export type TraceEvalJudgeDimensionId =
  | "answer-usefulness"
  | "source-faithfulness"
  | "evidence-sufficiency"
  | "uncertainty-handling"
  | "run-discipline";

export interface TraceEvalJudgeRubricDimension {
  description: string;
  id: TraceEvalJudgeDimensionId;
  title: string;
}

export interface TraceEvalJudgeDimensionScore {
  id: TraceEvalJudgeDimensionId;
  rationale: string;
  score: number;
  title: string;
}

export interface TraceEvalJudgeResult {
  action: TraceEvalJudgeAction;
  deterministicFailures: TraceEvalCheck[];
  dimensions: TraceEvalJudgeDimensionScore[];
  evaluatedAt: string;
  model: string;
  overallScore: number;
  rationale: string;
  summary: string;
}

export interface TraceEvalJudgeContext {
  answer: string;
  deterministicChecks: TraceEvalCheck[];
  deterministicFailures: TraceEvalCheck[];
  prompt: string;
  rubric: TraceEvalJudgeRubricDimension[];
  sources: TraceEvalSource[];
  trace: TraceEvalTraceItem[];
  usage: {
    durationMs?: number;
    totalTokens?: number;
  };
}

export const traceEvalJudgeDimensionSchema = z.object({
  id: z.enum([
    "answer-usefulness",
    "source-faithfulness",
    "evidence-sufficiency",
    "uncertainty-handling",
    "run-discipline",
  ]),
  rationale: z.string().min(1),
  score: z.number().min(0).max(1),
  title: z.string().min(1),
});

export const traceEvalJudgeStreamSchema = z.object({
  action: z.enum([
    "ready",
    "needs-revision",
    "rerun-research",
    "investigate-failure",
  ]),
  dimensions: z.array(traceEvalJudgeDimensionSchema).min(1),
  overallScore: z.number().min(0).max(1),
  rationale: z.string().min(1),
  summary: z.string().min(1),
});

export type TraceEvalJudgeStreamObject = z.infer<
  typeof traceEvalJudgeStreamSchema
>;

export const traceEvalJudgeRubric: TraceEvalJudgeRubricDimension[] = [
  {
    description:
      "Whether the final answer is directly useful for the user's research request.",
    id: "answer-usefulness",
    title: "Answer usefulness",
  },
  {
    description:
      "Whether claims in the answer stay faithful to the visible sources.",
    id: "source-faithfulness",
    title: "Source faithfulness",
  },
  {
    description:
      "Whether the run gathered enough evidence for the requested comparison or recommendation.",
    id: "evidence-sufficiency",
    title: "Evidence sufficiency",
  },
  {
    description:
      "Whether the answer names uncertainty, missing context, or conflicting evidence when needed.",
    id: "uncertainty-handling",
    title: "Uncertainty handling",
  },
  {
    description:
      "Whether the run followed the expected process: use search for current facts, expose sources, avoid bypassing required tools, and explain failures or weak evidence.",
    id: "run-discipline",
    title: "Run discipline",
  },
];

export function buildTraceEvalJudgeContext(
  snapshot: TraceEvalSnapshot
): TraceEvalJudgeContext {
  return {
    answer: snapshot.latestAnswer,
    deterministicChecks: snapshot.checks,
    deterministicFailures: snapshot.checks.filter(
      (check) => check.status === "failed"
    ),
    prompt: snapshot.latestPrompt ?? "",
    rubric: traceEvalJudgeRubric,
    sources: snapshot.sources,
    trace: snapshot.trace,
    usage: {
      durationMs: snapshot.durationMs,
      totalTokens: snapshot.totalTokens,
    },
  };
}

const investigateFailureIds = new Set(["provider-error", "tool-error"]);

export function resolveTraceEvalJudgeAction({
  deterministicFailures,
  overallScore,
}: {
  deterministicFailures: TraceEvalCheck[];
  overallScore: number;
}): TraceEvalJudgeAction {
  if (
    deterministicFailures.some((failure) =>
      investigateFailureIds.has(failure.id)
    )
  ) {
    return "investigate-failure";
  }

  if (deterministicFailures.length > 0) {
    return "rerun-research";
  }

  if (overallScore >= 0.8) {
    return "ready";
  }

  return "needs-revision";
}

export function completeTraceEvalJudgeResult({
  deterministicFailures,
  evaluatedAt,
  judge,
  model,
}: {
  deterministicFailures: TraceEvalCheck[];
  evaluatedAt: string;
  judge: TraceEvalJudgeStreamObject;
  model: string;
}): TraceEvalJudgeResult {
  return {
    ...judge,
    action: resolveTraceEvalJudgeAction({
      deterministicFailures,
      overallScore: judge.overallScore,
    }),
    deterministicFailures,
    evaluatedAt,
    model,
  };
}

export function formatTraceEvalJudgePrompt(
  context: TraceEvalJudgeContext
): string {
  return [
    "Evaluate this AI research-agent run.",
    "",
    "User prompt:",
    context.prompt || "No user prompt captured.",
    "",
    "Final answer:",
    context.answer || "No final answer captured.",
    "",
    "Deterministic checks:",
    JSON.stringify(context.deterministicChecks, null, 2),
    "",
    "Deterministic failures:",
    JSON.stringify(context.deterministicFailures, null, 2),
    "",
    "Execution trace:",
    JSON.stringify(context.trace, null, 2),
    "",
    "Sources:",
    JSON.stringify(context.sources, null, 2),
    "",
    "Usage:",
    JSON.stringify(context.usage, null, 2),
    "",
    "Rubric dimensions:",
    JSON.stringify(context.rubric, null, 2),
  ].join("\n");
}

const greetingPattern =
  /^(?:hi|hello|hey|yo|sup|hola|bonjour|你好|您好|嗨|哈喽|在吗)[!.?]*$/i;

const researchIntentPattern =
  /\b(research|compare|comparison|evaluate|analysis|analyze|explain|latest|current|today|recommend|recommendation|pick|should|versus|vs\.?|source|sources|cite|search)\b|研究|调研|比较|分析|解释|最新|推荐|检索|搜索|资料|来源/u;

const minimumResearchPromptLength = 20;

export function hasTraceEvalResearchIntent(prompt: string | null) {
  const normalizedPrompt = prompt?.trim() ?? "";

  if (normalizedPrompt.length === 0) {
    return false;
  }

  if (greetingPattern.test(normalizedPrompt)) {
    return false;
  }

  return (
    normalizedPrompt.length >= minimumResearchPromptLength ||
    researchIntentPattern.test(normalizedPrompt)
  );
}

import type { TraceEvalRunRecord } from "./trace-eval-run-record";
import { isTraceEvalRefusalAnswer } from "./trace-eval-run-state";

export type TraceEvalRunOutcome =
  | {
      detail: string;
      kind: "empty";
      shouldJudge: false;
      title: string;
    }
  | {
      detail: string;
      kind: "running";
      shouldJudge: false;
      title: string;
    }
  | {
      detail: string;
      kind: "skipped";
      reason: "non-research-turn";
      shouldJudge: false;
      title: string;
    }
  | {
      detail: string;
      kind: "failed-run";
      reason: "provider-error" | "refusal" | "missing-answer";
      shouldJudge: false;
      title: string;
    }
  | {
      detail: string;
      kind: "evaluated";
      shouldJudge: true;
      title: string;
    };

export function classifyTraceEvalRunOutcome({
  error,
  record,
}: {
  error?: Error | null;
  record: TraceEvalRunRecord;
}): TraceEvalRunOutcome {
  if (error) {
    return {
      detail: error.message,
      kind: "failed-run",
      reason: "provider-error",
      shouldJudge: false,
      title: "Run failed before evaluation",
    };
  }

  if (record.status === "empty") {
    return {
      detail: "Run a research question to populate trace and eval.",
      kind: "empty",
      shouldJudge: false,
      title: "No run yet",
    };
  }

  if (record.status === "running") {
    return {
      detail: "The latest run is still streaming.",
      kind: "running",
      shouldJudge: false,
      title: "Run in progress",
    };
  }

  if (!record.hasResearchIntent) {
    return {
      detail:
        "This turn looks like casual chat, so trace and eval are skipped without affecting the agent conversation.",
      kind: "skipped",
      reason: "non-research-turn",
      shouldJudge: false,
      title: "Skipped non-research turn",
    };
  }

  if (isTraceEvalRefusalAnswer(record.latestAnswer)) {
    return {
      detail:
        "The assistant refused the run. Retry with a research prompt that allows live search and source-grounded output.",
      kind: "failed-run",
      reason: "refusal",
      shouldJudge: false,
      title: "Run ended in refusal",
    };
  }

  if (!record.latestAnswer.trim()) {
    return {
      detail:
        "The run completed without a final answer. Retry the run before evaluating quality.",
      kind: "failed-run",
      reason: "missing-answer",
      shouldJudge: false,
      title: "Run completed without answer",
    };
  }

  return {
    detail: "The run produced a research answer and can be evaluated.",
    kind: "evaluated",
    shouldJudge: true,
    title: "Ready for evaluation",
  };
}

import {
  getToolName,
  isTextUIPart,
  isToolUIPart,
  type LanguageModelUsage,
  type SourceUrlUIPart,
  type UIMessage,
} from "ai";
import { hasTraceEvalResearchIntent } from "./trace-eval-prompt-intent";

export interface TraceEvalAgentMessageMetadata {
  finishedAt?: number;
  finishReason?: string;
  model?: string;
  runId?: string;
  searchTool?: string;
  startedAt?: number;
  totalUsage?: LanguageModelUsage;
}

export type TraceEvalAgentMessage = UIMessage<TraceEvalAgentMessageMetadata>;

export type TraceEvalStatus = "empty" | "running" | "complete";

export interface TraceEvalSource {
  id: string;
  origin: "markdown-link" | "source-part";
  title: string;
  url: string;
}

export interface TraceEvalSearchCall {
  id: string;
  input?: unknown;
  name: string;
  status: "running" | "passed" | "failed";
}

export interface TraceEvalRunRecord {
  durationMs?: number;
  finishReason?: string;
  hasResearchIntent: boolean;
  latestAnswer: string;
  latestPrompt: string | null;
  model?: string;
  runId?: string;
  searchCalls: TraceEvalSearchCall[];
  searchTool: string;
  sources: TraceEvalSource[];
  status: TraceEvalStatus;
  totalTokens?: number;
  usage?: LanguageModelUsage;
}

const markdownLinkPattern = /\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/g;

function getMessageText(message: UIMessage): string {
  return message.parts
    .filter(isTextUIPart)
    .map((part) => part.text)
    .join("");
}

function getLatestUserPrompt(messages: UIMessage[]): string | null {
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index];

    if (message?.role === "user") {
      return getMessageText(message).trim() || null;
    }
  }

  return null;
}

function getAssistantMessages(messages: UIMessage[]) {
  return messages.filter(
    (message): message is TraceEvalAgentMessage => message.role === "assistant"
  );
}

function getLatestAssistant(messages: UIMessage[]) {
  return getAssistantMessages(messages).at(-1) ?? null;
}

function getSearchToolName(messages: UIMessage[]) {
  return getLatestAssistant(messages)?.metadata?.searchTool ?? "web_search";
}

function getToolTraceStatus(state: string): TraceEvalSearchCall["status"] {
  if (state === "output-error") {
    return "failed";
  }

  if (state === "output-available") {
    return "passed";
  }

  return "running";
}

function getSearchCalls(messages: UIMessage[]): TraceEvalSearchCall[] {
  const searchToolName = getSearchToolName(messages);

  return getAssistantMessages(messages)
    .flatMap((message) => message.parts.filter(isToolUIPart))
    .filter((part) => getToolName(part) === searchToolName)
    .map((part, index) => ({
      id: `${part.toolCallId}-${index}`,
      input: part.input,
      name: searchToolName,
      status: getToolTraceStatus(part.state),
    }));
}

function toTraceEvalSource(part: SourceUrlUIPart): TraceEvalSource {
  return {
    id: part.sourceId,
    origin: "source-part",
    title: part.title || part.url,
    url: part.url,
  };
}

function getMarkdownLinkSources(text: string): TraceEvalSource[] {
  return Array.from(
    text.matchAll(markdownLinkPattern),
    ([match, rawTitle, rawUrl]) => {
      const url = rawUrl ?? match;
      const title = rawTitle?.trim() || url;

      return {
        id: match,
        origin: "markdown-link",
        title,
        url,
      };
    }
  );
}

function getSources(messages: UIMessage[]): TraceEvalSource[] {
  const latestAssistant = getLatestAssistant(messages);

  if (!latestAssistant) {
    return [];
  }

  const sources = [
    ...latestAssistant.parts.flatMap((part) =>
      part.type === "source-url" ? [toTraceEvalSource(part)] : []
    ),
    ...getMarkdownLinkSources(getMessageText(latestAssistant)),
  ];

  return Array.from(
    new Map(sources.map((source) => [source.url, source])).values()
  );
}

function getDurationMs(metadata: TraceEvalAgentMessageMetadata | undefined) {
  if (!(metadata?.startedAt && metadata.finishedAt)) {
    return;
  }

  return Math.max(0, metadata.finishedAt - metadata.startedAt);
}

export function buildTraceEvalRunRecord(
  messages: UIMessage[],
  isBusy: boolean
): TraceEvalRunRecord {
  const latestPrompt = getLatestUserPrompt(messages);
  const latestAssistant = getLatestAssistant(messages);
  const latestAnswer = latestAssistant
    ? getMessageText(latestAssistant).trim()
    : "";
  const metadata = latestAssistant?.metadata;
  let status: TraceEvalStatus = "complete";

  if (messages.length === 0) {
    status = "empty";
  } else if (isBusy) {
    status = "running";
  }

  return {
    durationMs: getDurationMs(metadata),
    finishReason: metadata?.finishReason,
    hasResearchIntent: hasTraceEvalResearchIntent(latestPrompt),
    latestAnswer,
    latestPrompt,
    model: metadata?.model,
    runId: metadata?.runId,
    searchCalls: getSearchCalls(messages),
    searchTool: getSearchToolName(messages),
    sources: getSources(messages),
    status,
    totalTokens: metadata?.totalUsage?.totalTokens,
    usage: metadata?.totalUsage,
  };
}

import { hasTraceEvalResearchIntent } from "./trace-eval-prompt-intent";
import type { TraceEvalSnapshot } from "./trace-eval-snapshot";

const refusalPatterns = [
  /\bi cannot assist with that request\b/i,
  /\bi can't assist with that request\b/i,
  /\bi cannot help with that request\b/i,
  /\bi can't help with that request\b/i,
  /\bi'm sorry, but i cannot assist\b/i,
  /\bi'm sorry, but i can't assist\b/i,
];

export function isTraceEvalRefusalAnswer(answer: string) {
  const normalizedAnswer = answer.trim();

  if (normalizedAnswer.length === 0) {
    return false;
  }

  return refusalPatterns.some((pattern) => pattern.test(normalizedAnswer));
}

export function shouldEvaluateTraceEvalSnapshot(snapshot: TraceEvalSnapshot) {
  return Boolean(
    snapshot.status === "complete" &&
      hasTraceEvalResearchIntent(snapshot.latestPrompt) &&
      snapshot.latestAnswer.trim() &&
      !isTraceEvalRefusalAnswer(snapshot.latestAnswer)
  );
}

export function hasTraceEvalFailedGeneration(snapshot: TraceEvalSnapshot) {
  return Boolean(
    snapshot.status === "complete" &&
      hasTraceEvalResearchIntent(snapshot.latestPrompt) &&
      !snapshot.latestAnswer.trim()
  );
}

import type { UIMessage } from "ai";
import {
  buildTraceEvalRunRecord,
  type TraceEvalRunRecord,
  type TraceEvalSource,
  type TraceEvalStatus,
} from "./trace-eval-run-record";

export type {
  TraceEvalAgentMessage,
  TraceEvalSource,
  TraceEvalStatus,
} from "./trace-eval-run-record";

export type TraceItemKind = "user" | "model" | "tool" | "source" | "usage";

export interface TraceEvalTraceItem {
  detail: string;
  id: string;
  kind: TraceItemKind;
  metric?: string;
  status: "pending" | "running" | "passed" | "failed";
  title: string;
}

export interface TraceEvalCheck {
  detail: string;
  id: string;
  status: "passed" | "failed" | "running" | "skipped";
  title: string;
}

export interface TraceEvalSummary {
  failed: number;
  passed: number;
  skipped: number;
  total: number;
}

export interface TraceEvalSnapshot {
  checks: TraceEvalCheck[];
  durationMs?: number;
  latestAnswer: string;
  latestPrompt: string | null;
  runId?: string;
  score: number;
  sources: TraceEvalSource[];
  status: TraceEvalStatus;
  summary: TraceEvalSummary;
  totalTokens?: number;
  trace: TraceEvalTraceItem[];
}

const minimumAnswerLength = 120;

function getModelTraceStatus(
  record: TraceEvalRunRecord
): TraceEvalTraceItem["status"] {
  if (!record.model) {
    return "pending";
  }

  return record.status === "running" ? "running" : "passed";
}

function buildTraceItems({
  record,
}: {
  record: TraceEvalRunRecord;
}): TraceEvalTraceItem[] {
  const trace: TraceEvalTraceItem[] = [];

  trace.push({
    detail:
      record.latestPrompt ?? "No research request has been submitted yet.",
    id: "request",
    kind: "user",
    status: record.hasResearchIntent ? "passed" : "pending",
    title: "Research request",
  });

  trace.push({
    detail: record.model
      ? `${record.model} streaming through AI Gateway.`
      : "The model run will appear after the first assistant response starts.",
    id: "model",
    kind: "model",
    status: getModelTraceStatus(record),
    title: "Gateway model run",
  });

  trace.push(
    ...record.searchCalls.map((call) => ({
      detail: call.input
        ? JSON.stringify(call.input)
        : "Search input is still streaming.",
      id: call.id,
      kind: "tool" as const,
      status: call.status,
      title: call.name,
    }))
  );

  if (record.sources.length > 0) {
    trace.push({
      detail: record.sources.map((source) => source.title).join(", "),
      id: "sources",
      kind: "source",
      metric: `${record.sources.length} sources`,
      status: "passed",
      title: "Grounding sources",
    });
  }

  if (record.usage?.totalTokens !== undefined) {
    trace.push({
      detail: [
        `Input ${record.usage.inputTokens ?? "unknown"}`,
        `Output ${record.usage.outputTokens ?? "unknown"}`,
      ].join(" / "),
      id: "usage",
      kind: "usage",
      metric: `${record.usage.totalTokens} tokens`,
      status: "passed",
      title: "Token usage",
    });
  }

  return trace;
}

function buildChecks({
  record,
}: {
  record: TraceEvalRunRecord;
}): TraceEvalCheck[] {
  const completedSearches = record.searchCalls.filter(
    (call) => call.status === "passed"
  );

  return [
    buildResearchQueryCheck(record.hasResearchIntent),
    buildSearchCheck({
      completedSearchCount: completedSearches.length,
      hasPrompt: record.hasResearchIntent,
      hasSearchInFlight:
        record.status === "running" && record.searchCalls.length > 0,
    }),
    buildSourceCoverageCheck({
      hasPrompt: record.hasResearchIntent,
      sourceCount: record.sources.length,
    }),
    buildAnswerShapeCheck({
      answerLength: record.latestAnswer.length,
      hasPrompt: record.hasResearchIntent,
      isBusy: record.status === "running",
    }),
  ];
}

function buildResearchQueryCheck(hasPrompt: boolean): TraceEvalCheck {
  return {
    detail: hasPrompt
      ? "A research question is present in the session."
      : "Submit a research question instead of a casual chat turn to start the evaluation.",
    id: "research-query",
    status: hasPrompt ? "passed" : "skipped",
    title: "Research query present",
  };
}

function buildSearchCheck({
  completedSearchCount,
  hasPrompt,
  hasSearchInFlight,
}: {
  completedSearchCount: number;
  hasPrompt: boolean;
  hasSearchInFlight: boolean;
}): TraceEvalCheck {
  let status: TraceEvalCheck["status"] = "skipped";

  if (completedSearchCount > 0) {
    status = "passed";
  } else if (hasSearchInFlight) {
    status = "running";
  } else if (hasPrompt) {
    status = "failed";
  }

  return {
    detail:
      completedSearchCount > 0
        ? "The agent used the configured Gateway web search tool."
        : "The agent should call the configured web search tool before finalizing current facts.",
    id: "gateway-search",
    status,
    title: "Gateway web search executed",
  };
}

function buildSourceCoverageCheck({
  hasPrompt,
  sourceCount,
}: {
  hasPrompt: boolean;
  sourceCount: number;
}): TraceEvalCheck {
  let status: TraceEvalCheck["status"] = "skipped";

  if (sourceCount >= 2) {
    status = "passed";
  } else if (hasPrompt) {
    status = "failed";
  }

  return {
    detail:
      sourceCount >= 2
        ? `${sourceCount} source links are available on the latest assistant answer.`
        : "The final answer should expose at least two source links.",
    id: "source-coverage",
    status,
    title: "Sources attached",
  };
}

function buildAnswerShapeCheck({
  answerLength,
  hasPrompt,
  isBusy,
}: {
  answerLength: number;
  hasPrompt: boolean;
  isBusy: boolean;
}): TraceEvalCheck {
  let status: TraceEvalCheck["status"] = "skipped";

  if (answerLength >= minimumAnswerLength) {
    status = "passed";
  } else if (isBusy) {
    status = "running";
  } else if (hasPrompt) {
    status = "failed";
  }

  return {
    detail:
      answerLength >= minimumAnswerLength
        ? "The answer contains enough substance for review."
        : "The response is still missing a substantive research summary.",
    id: "answer-shape",
    status,
    title: "Research answer shape",
  };
}

function summarizeChecks(checks: TraceEvalCheck[]): TraceEvalSummary {
  return {
    failed: checks.filter((check) => check.status === "failed").length,
    passed: checks.filter((check) => check.status === "passed").length,
    skipped: checks.filter((check) => check.status === "skipped").length,
    total: checks.length,
  };
}

export function buildTraceEvalSnapshotFromRunRecord(
  record: TraceEvalRunRecord
): TraceEvalSnapshot {
  const checks = buildChecks({
    record,
  });
  const summary = summarizeChecks(checks);

  return {
    checks,
    durationMs: record.durationMs,
    latestAnswer: record.latestAnswer,
    latestPrompt: record.latestPrompt,
    runId: record.runId,
    score: summary.total === 0 ? 0 : summary.passed / summary.total,
    sources: record.sources,
    status: record.status,
    summary,
    totalTokens: record.totalTokens,
    trace: buildTraceItems({ record }),
  };
}

export function buildTraceEvalSnapshot(
  messages: UIMessage[],
  isBusy: boolean
): TraceEvalSnapshot {
  return buildTraceEvalSnapshotFromRunRecord(
    buildTraceEvalRunRecord(messages, isBusy)
  );
}
